={
  "query": "query ClosedPullsForClient($clientId: ID!) { pulls(filter: { client: { id: { eq: $clientId } }, stage: { eq: CLOSED } }) { edges { node { id returnDate creditGiven } } } }",
  "variables": { "clientId": "{{ $('Twenty Pull Webhook').item.json.body.record.clientId }}" }
}

parameters.jsCode:
const pulls = $input.first().json.data?.pulls?.edges?.map(e => e.node) ?? [];
if (!pulls.length) return [{ json: { score: 5, clientId: $('Twenty Pull Webhook').first().json.body.record.clientId } }];

const total = pulls.length;
const credited = pulls.filter(p => p.creditGiven).length;
// Placeholder scoring — refine with on-time return + damage flags when fields exist
const creditRate = credited / total;
const score = Math.max(1, Math.min(10, Math.round(5 + creditRate * 5)));

return [{ json: { score, clientId: $('Twenty Pull Webhook').first().json.body.record.clientId } }];

